    vector<tuple<int, int, int>> f;
    for (int j1 = 0; j1 < m; j1++) {
      for (int j2 = j1 + 1; j2 < m; j2++) {
        if (up[j1][j2] != -1 && down[j1][j2].size()) {
          int i1 = up[j1][j2];
          int i2 = down[j1][j2].back();
          f.push_back({(i2 - i1 + 1) * (j2 - j1 + 1), j1, j2});
        }
      }
    }

    for (int j1 = 0; j1 < m; j1++) {
      for (int j2 = j1 + 1; j2 < m; j2++) {
        if (g[i][j1] == 1 && g[i][j2] == 1) {
          up[j1][j2] = i;
          down[j1][j2].pop_back();
        }
      }
    }

    for (int j1 = 0; j1 < m; j1++) {
      for (int j2 = j1 + 1; j2 < m; j2++) {
        if (up[j1][j2] != -1 && down[j1][j2].size()) {
          int i1 = up[j1][j2];
          int i2 = down[j1][j2].back();
          f.push_back({(i2 - i1 + 1) * (j2 - j1 + 1), j1, j2});
        }
      }
    }

    make_unique(f);
    for (int j = 0; j < m; j++) {
      st.range_chmax(j, j + 1, 1e18);
    }

    for (auto &[v, l, r] : f) {
      st.range_chmin(l, r + 1, v);
    }

    for (int j = 0; j < m; j++) {
      ans[i][j] = st.range_min(j, j + 1);
    }

  }

  if (swapped) {
    vector<vector<int>> nans(m, vector<int>(n));
    for (int i = 0; i < n; i++) {
      for (int j = 0; j < m; j++) {
        nans[j][i] = ans[i][j];
      }
    }
    swap(n, m);
    swap(ans, nans);
  }  

  for (int i = 0; i < n; i++) {
    for (int j = 0; j < m; j++) {
      if (ans[i][j] > n * m) ans[i][j] = 0;
      cout << ans[i][j] << " \n"[j == m - 1];
    }
  }

}

